module gray_counter_core #(
    parameter integer WIDTH = 4
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             enable,
    input  logic             clear,
    output logic [WIDTH-1:0] gray_value,
    output logic [WIDTH-1:0] bin_value,
    output logic             done
);

    // SSOT ERR_PARAM_WIDTH: illegal WIDTH must fail build/elaboration.
    localparam integer WIDTH_CHECK = (WIDTH >= 2) ? WIDTH : -1;
    logic [WIDTH_CHECK-1:0] width_must_be_ge_2;

    // SSOT FSM states.
    localparam [2:0] IDLE       = 3'd0,
                     RUN        = 3'd1,
                     WRAP_PULSE = 3'd2,
                     CLEARED    = 3'd3,
                     RESET      = 3'd4;

    logic [2:0] state;
    logic [2:0] next_state;

    // Architectural state (function_model.state_variables).
    logic [WIDTH-1:0] gray_state;
    logic [WIDTH-1:0] bin_state;
    logic             done_state;

    // Gray decode helper chain (no loops/functions per coding rules).
    logic [WIDTH-1:0] gray_to_bin_s1;
    logic [WIDTH-1:0] gray_to_bin_s2;
    logic [WIDTH-1:0] gray_to_bin_s3;
    logic [WIDTH-1:0] gray_to_bin_s4;
    logic [WIDTH-1:0] gray_to_bin_s5;
    logic [WIDTH-1:0] gray_to_bin_cur;

    // Advance-path helpers.
    logic [WIDTH-1:0] internal_bin_next;
    logic [WIDTH-1:0] gray_next;
    logic             wrap_detect;

    assign width_must_be_ge_2 = {WIDTH_CHECK{1'b0}};

    // Combinational gray->bin decode of current gray_state.
    assign gray_to_bin_s1  = gray_state ^ (gray_state >> 1);
    assign gray_to_bin_s2  = gray_to_bin_s1 ^ (gray_to_bin_s1 >> 2);
    assign gray_to_bin_s3  = gray_to_bin_s2 ^ (gray_to_bin_s2 >> 4);
    assign gray_to_bin_s4  = gray_to_bin_s3 ^ (gray_to_bin_s3 >> 8);
    assign gray_to_bin_s5  = gray_to_bin_s4 ^ (gray_to_bin_s4 >> 16);
    assign gray_to_bin_cur = gray_to_bin_s5 ^ (gray_to_bin_s5 >> 32);

    // S1_COMPUTE for GC_TXN_ADVANCE.
    assign internal_bin_next = gray_to_bin_cur + {{(WIDTH-1){1'b0}}, 1'b1};
    assign gray_next         = internal_bin_next ^ (internal_bin_next >> 1);
    assign wrap_detect       = (gray_to_bin_cur == {WIDTH{1'b1}});

    // Next-state decode. clear priority over enable (invariant_3).
    always @(*) begin
        next_state = state;
        case (state)
            RESET: begin
                next_state = IDLE;
            end

            IDLE: begin
                if (clear) begin
                    next_state = CLEARED;
                end else if (enable) begin
                    next_state = RUN;
                end else begin
                    next_state = IDLE;
                end
            end

            RUN: begin
                if (clear) begin
                    next_state = CLEARED;
                end else if (!enable) begin
                    next_state = IDLE;
                end else if (wrap_detect) begin
                    next_state = WRAP_PULSE;
                end else begin
                    next_state = RUN;
                end
            end

            WRAP_PULSE: begin
                if (clear) begin
                    next_state = CLEARED;
                end else if (enable) begin
                    next_state = RUN;
                end else begin
                    next_state = IDLE;
                end
            end

            CLEARED: begin
                if (!clear) begin
                    next_state = IDLE;
                end else begin
                    next_state = CLEARED;
                end
            end

            default: begin
                next_state = RESET;
            end
        endcase
    end

    // S0_SAMPLE + S2_COMMIT.
    // reset dominates all synchronous controls (invariant_4).
    // hold transaction forces done_state low (GC_TXN_HOLD side effect/output rules).
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state      <= RESET;
            gray_state <= {WIDTH{1'b0}};
            bin_state  <= {WIDTH{1'b0}};
            done_state <= 1'b0;
        end else begin
            state <= next_state;

            if (clear) begin
                gray_state <= {WIDTH{1'b0}};
                bin_state  <= {WIDTH{1'b0}};
                done_state <= 1'b0;
            end else if (enable) begin
                // latency=1: commit outputs from accepted control on this edge.
                gray_state <= gray_next;
                bin_state  <= internal_bin_next;
                done_state <= wrap_detect;
            end else begin
                // GC_TXN_HOLD:
                // - gray_hold: gray_value remains gray_state
                // - bin_hold:  bin_value remains gray_to_bin(gray_state)
                // - done_hold: done is 0 in hold cycles
                gray_state <= gray_state;
                bin_state  <= gray_to_bin_cur;
                done_state <= 1'b0;
            end
        end
    end

    // Observable outputs:
    // invariant_0: gray_value is legal Gray encoding of bin_state by construction.
    // invariant_1: bin_value is combinational decode of current gray_value/gray_state.
    // invariant_2: done is one-cycle wrap pulse because non-wrap paths force done_state low.
    assign gray_value = gray_state;
    assign done       = done_state;
    assign bin_value  = gray_to_bin_cur;

endmodule

